#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>

#include <unistd.h>
#include <stdint.h>
#include <stdlib.h>

__inline__ uint64_t rdtsc() 
{
     uint32_t lo, hi;
     __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
     return (uint64_t)hi << 32 | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#include <sys/time.h>

struct timeval starttime;
struct timeval endtime;

#define startTime() \
{ \
  gettimeofday(&starttime, 0); \
}
#define stopTime(valusecs) \
{ \
  gettimeofday(&endtime, 0); \
  valusecs = (endtime.tv_sec-starttime.tv_sec)*1000000+endtime.tv_usec-starttime.tv_usec; \
}

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

#define MIN(a, b) ((a)<=(b) ? (a) : (b))

__global__ void pathfinder_step(int* src, int* dst, int* wall_row, int cols) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n >= cols) return;

    int min = src[n];
    if (n > 0) {
        int left = src[n-1];
        if (left < min) min = left;
    }
    if (n < cols-1) {
        int right = src[n+1];
        if (right < min) min = right;
    }
    dst[n] = wall_row[n] + min;
}

void check_cuda_error(cudaError_t err, const char* msg) {
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA Error: %s (%s)\n", cudaGetErrorString(err), msg);
        exit(1);
    }
}

void
init(int argc, char** argv)
{
	if(argc==3){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
	}else{
                printf("Usage: pathfiner width num_of_steps\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; n<rows; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src_host, *dst_host, *temp_host;
    int *src_dev, *dst_dev, *wall_row_dev;
    int min;

    dst_host = result;
    src_host = new int[cols];

    // Allocate device memory
    check_cuda_error(cudaMalloc(&src_dev, cols * sizeof(int)), "malloc src");
    check_cuda_error(cudaMalloc(&dst_dev, cols * sizeof(int)), "malloc dst");
    check_cuda_error(cudaMalloc(&wall_row_dev, cols * sizeof(int)), "malloc wall_row");

    // Initialize src_dev with result (wall[0])
    check_cuda_error(cudaMemcpy(src_dev, dst_host, cols * sizeof(int), cudaMemcpyHostToDevice), "copy init");

    pin_stats_reset();

    int block_size = 256;
    int num_blocks = (cols + block_size - 1) / block_size;

    for (int t = 0; t < rows-1; t++) {
        // Copy wall[t+1] to device
        check_cuda_error(cudaMemcpy(wall_row_dev, wall[t+1], cols * sizeof(int), cudaMemcpyHostToDevice), "copy wall");

        // Launch kernel: dst = wall + min(src neighbors)
        // Current src is in src_dev, result will be in dst_dev
        pathfinder_step<<<num_blocks, block_size>>>(src_dev, dst_dev, wall_row_dev, cols);
        check_cuda_error(cudaGetLastError(), "kernel launch");
        check_cuda_error(cudaDeviceSynchronize(), "sync");

        // Swap device pointers for next iteration
        int* temp_dev = src_dev;
        src_dev = dst_dev;
        dst_dev = temp_dev;
    }

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

    // Copy final result back to host (dst_host points to result array)
    // After the loop, the latest data is in src_dev because we swapped at the end of the last iteration
    check_cuda_error(cudaMemcpy(dst_host, src_dev, cols * sizeof(int), cudaMemcpyDeviceToHost), "copy result");

#ifdef BENCH_PRINT

    for (int i = 0; i < cols; i++)
            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; i < cols; i++)
            printf("%d ",dst_host[i]) ;

    printf("\n") ;

#endif

    delete [] data;
    delete [] wall;
    delete [] dst_host;
    delete [] src_host;

    cudaFree(src_dev);
    cudaFree(dst_dev);
    cudaFree(wall_row_dev);
}

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}
